// src/pages/HomeScreen.js
import React, { useMemo, useState } from "react";
import {
  SafeAreaView,
  View,
  Text,
  StyleSheet,
  Image,
  TextInput,
  TouchableOpacity,
  ScrollView,
  Platform,
  useWindowDimensions,
} from "react-native";

const nalicoreLogo = require("../../assets/nalicore_logo.png");

export default function HomeScreen() {
  const { width } = useWindowDimensions();

  // breakpoints (keep yours)
  const isSmall = width < 420;
  const isMobile = width < 768;
  const isDesktop = width >= 1024;

  // centered container width for web/tablet
  const containerMaxWidth = isDesktop ? 760 : 680;

  // responsive typography (keep yours)
  const titleSize = isSmall ? 20 : 22;
  const labelSize = isSmall ? 16 : 18;
  const valueSize = isSmall ? 16 : 18;
  const navTextSize = isSmall ? 18 : 20;

  const [query, setQuery] = useState(
    "Total borne 10 entre\nenfant noir chez le boss"
  );

  const resolved = useMemo(
    () => ({
      quartier: "Odza",
      secteur: "Borne 10",
      sousSecteur: "Total borne 10",
      entree: "Enfant Noir",
      lieu: "Chez le Boss",
      banoc: "Q5TCL",
      latitude: 3.7862,
      longitude: 111.53045,
    }),
    []
  );

  const onResolve = () => console.log("Resolve:", query);
  const onNavigate = () =>
    console.log("Navigate:", resolved.latitude, resolved.longitude);

  return (
    <SafeAreaView style={styles.safe}>
      <ScrollView
        contentContainerStyle={styles.scroll}
        showsVerticalScrollIndicator={false}
        keyboardShouldPersistTaps="handled"
      >
        <View
          style={[
            styles.container,
            {
              maxWidth: containerMaxWidth,
              paddingHorizontal: isMobile ? 18 : 22,
              paddingTop: isMobile ? 16 : 20,
            },
          ]}
        >
          {/* Header */}
          <View style={[styles.header, { gap: 12 }]}>
            <Image
              source={nalicoreLogo}
              style={[styles.logo, { width: isSmall ? 160 : 190, height: 52 }]}
              resizeMode="contain"
            />

            <View style={{ flex: 1 }} />

            {/* ✅ FIX: EXACTLY like mock (2 lines only) */}
            <Text
              style={[
                styles.tagline,
                {
                  fontSize: isSmall ? 15 : 17,
                  lineHeight: isSmall ? 21 : 24,
                  // give enough width so it won't split into 3 lines
                  maxWidth: isMobile ? 260 : 340,
                },
              ]}
              numberOfLines={2}
            >
              Natural Address{"\n"}Location Infrastructure
            </Text>
          </View>

          {/* Search + Resolve */}
          <View
            style={[
              styles.searchRow,
              {
                // ✅ FIX: keep SAME ROW on mobile like mock
                flexDirection: "row",
                // ✅ FIX: no wrapping (your current wrap is why button drops below)
                flexWrap: "nowrap",
                gap: 10,
              },
            ]}
          >
            <View style={[styles.searchInputWrap, { flex: 1 }]}>
              <Text style={styles.searchIcon}>⌕</Text>

              <TextInput
                value={query}
                onChangeText={setQuery}
                style={[
                  styles.searchInput,
                  { fontSize: isSmall ? 16 : 18, lineHeight: isSmall ? 22 : 24 },
                ]}
                placeholder="Type an address…"
                placeholderTextColor="rgba(15,23,42,0.45)"
                multiline
                numberOfLines={2}
                // ✅ FIX: remove inner scrolling
                scrollEnabled={false}
                // ✅ FIX: prevents weird web focus outline + keeps it clean
                underlineColorAndroid="transparent"
                textAlignVertical="center"
              />
            </View>

            <TouchableOpacity
              activeOpacity={0.9}
              style={[
                styles.resolveBtn,
                {
                  // mock button is a fixed block on the right
                  width: isMobile ? 150 : 170,
                  height: 64,
                },
              ]}
              onPress={onResolve}
            >
              <Text style={[styles.resolveText, { fontSize: isSmall ? 16 : 18 }]}>
                Resolve
              </Text>
            </TouchableOpacity>
          </View>

          {/* Card */}
          <View style={styles.card}>
            <Text style={[styles.cardTitle, { fontSize: titleSize }]}>
              Resolved Address
            </Text>

            <Row label="Quartier:" value={resolved.quartier} labelSize={labelSize} valueSize={valueSize} />
            <Row label="Secteur:" value={resolved.secteur} labelSize={labelSize} valueSize={valueSize} />
            <Row label="Sous-secteur:" value={resolved.sousSecteur} labelSize={labelSize} valueSize={valueSize} />
            <Row label="Entrée:" value={resolved.entree} labelSize={labelSize} valueSize={valueSize} />
            <Row label="Lieu:" value={resolved.lieu} labelSize={labelSize} valueSize={valueSize} />

            <View style={styles.row}>
              <Text style={[styles.label, { fontSize: labelSize }]}>BANOC:</Text>
              <View style={styles.banocPill}>
                <Text style={styles.banocText}>{resolved.banoc}</Text>
              </View>
            </View>

            {/* IMPORTANT: single-value lat/lng */}
            <Row
              label="Latitude:"
              value={Number(resolved.latitude).toFixed(5)}
              labelSize={labelSize}
              valueSize={valueSize}
            />
            <Row
              label="Longitude:"
              value={Number(resolved.longitude).toFixed(5)}
              labelSize={labelSize}
              valueSize={valueSize}
            />

            <TouchableOpacity
              activeOpacity={0.9}
              style={[styles.navBtn, { height: 60, marginTop: 16 }]}
              onPress={onNavigate}
            >
              <Text style={[styles.navIcon, { fontSize: isSmall ? 18 : 20 }]}>
                ⌖
              </Text>
              <Text style={[styles.navText, { fontSize: navTextSize }]}>
                Navigate to Location
              </Text>
            </TouchableOpacity>
          </View>

          <View style={{ height: isMobile ? 220 : 140 }} />
        </View>
      </ScrollView>
    </SafeAreaView>
  );
}

function Row({ label, value, labelSize, valueSize }) {
  return (
    <View style={styles.row}>
      <Text style={[styles.label, { fontSize: labelSize }]}>{label}</Text>
      <Text style={[styles.value, { fontSize: valueSize }]} numberOfLines={2}>
        {value}
      </Text>
    </View>
  );
}

const styles = StyleSheet.create({
  safe: { flex: 1, backgroundColor: "#E9ECF6" },
  scroll: { paddingBottom: 28 },

  container: {
    width: "100%",
    alignSelf: "center",
  },

  header: {
    width: "100%",
    flexDirection: "row",
    alignItems: "flex-start",
    justifyContent: "space-between",
    marginBottom: 18,
  },

  logo: { height: 52 },

  // ✅ FIX: closer to mock (less bold + correct tone)
  tagline: {
    textAlign: "right",
    color: "rgba(15, 23, 42, 0.65)",
    fontWeight: "600",
  },

  searchRow: {
    width: "100%",
    alignItems: "stretch",
    marginBottom: 18,
  },

  searchInputWrap: {
    backgroundColor: "rgba(255,255,255,0.65)",
    borderRadius: 16,
    borderWidth: 1,
    borderColor: "rgba(15,23,42,0.08)",
    paddingLeft: 44,
    paddingRight: 12,
    minHeight: 64,
    justifyContent: "center",
    ...Platform.select({
      ios: {
        shadowColor: "#000",
        shadowOpacity: 0.06,
        shadowRadius: 10,
        shadowOffset: { width: 0, height: 6 },
      },
      android: { elevation: 2 },
    }),
  },

  searchIcon: {
    position: "absolute",
    left: 16,
    top: 20,
    fontSize: 18,
    color: "rgba(15, 23, 42, 0.45)",
  },

  // ✅ FIX: ensure input doesn't create its own scroll; fixed height feel
  searchInput: {
    fontWeight: "800",
    color: "#0F172A",
    paddingVertical: 10,
    paddingRight: 6,
    // Web: remove outline-like look
    ...(Platform.OS === "web"
      ? { outlineStyle: "none" }
      : null),
  },

  resolveBtn: {
    borderRadius: 18,
    backgroundColor: "#2E59B7",
    alignItems: "center",
    justifyContent: "center",
    ...Platform.select({
      ios: {
        shadowColor: "#000",
        shadowOpacity: 0.10,
        shadowRadius: 12,
        shadowOffset: { width: 0, height: 10 },
      },
      android: { elevation: 4 },
    }),
  },

  resolveText: {
    color: "#FFFFFF",
    fontWeight: "900",
    letterSpacing: 0.2,
  },

  card: {
    width: "100%",
    backgroundColor: "rgba(255,255,255,0.65)",
    borderRadius: 20,
    borderWidth: 1,
    borderColor: "rgba(15,23,42,0.08)",
    padding: 18,
    ...Platform.select({
      ios: {
        shadowColor: "#000",
        shadowOpacity: 0.08,
        shadowRadius: 14,
        shadowOffset: { width: 0, height: 10 },
      },
      android: { elevation: 3 },
    }),
  },

  cardTitle: {
    fontWeight: "900",
    color: "#0F172A",
    marginBottom: 14,
  },

  row: {
    flexDirection: "row",
    alignItems: "center",
    marginBottom: 12,
    gap: 10,
  },

  label: {
    width: 130,
    color: "rgba(15,23,42,0.55)",
    fontWeight: "800",
  },

  value: {
    flex: 1,
    color: "#0F172A",
    fontWeight: "900",
